module top_module(clk, res, a, b, outp);input clk,res;
  input [31:0] a, b;
  reg [7:0] unused_exp_a,exp_b;
  output reg [8:0] outp;

  always @(posedge clk)
    begin
      unused_exp_a = a[30:23];
      exp_b = b[30:23];
      if(unused_exp_a >= exp_b)
        begin
        outp[7:0] = unused_exp_a - exp_b;
        outp[8] = 0;
        end
      else
        begin
          outp[7:0] = exp_b - unused_exp_a;
          outp[8] = 1;
        end
      if(res == 0)
        outp = 0;
    end
endmodule
